  ('police-f3743df6-moex-00010', 'police-f3743df6', 'police-f3743df6-moex-114-15a7b19c', 'sub-police-f3743df6-01', NULL, 'single_choice', '有關憲法第7條規定之平等權，下列敘述何者錯誤？', '["本條雖稱中華民國人民，在法律上一律平等，並不表示外國人不得享有平等權", "對於婦女當選名額之保障，不違反憲法第7條平等權之精神", "憲法第7條所定男女、宗教、種族、階級、黨派之分類事由，係採列舉方式", "憲法第7條適用範圍包括立法、行政及司法機關的公權力行為 51250、51350"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:17+00:00", "source_pdf_sha1": "cb62bb60fb06", "answer_pdf_sha1": "3fccc3dc4215", "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "512", "s": "0206", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中華民國憲法與警察專業英文", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "警察法制人員"}'::jsonb, NULL),
